class MultiSourceJWTVerifier:
    """
    Verifies JWT tokens from multiple sources (internal services, external APIs)
    each with their own signing configuration.
    
    Each source is identified by the 'iss' (issuer) claim in the token.
    """

    def __init__(self):
        self._source_configs: Dict[str, JWTConfig] = {}
        self._default_config: Optional[JWTConfig] = None

    def register_source(self, issuer: str, config: JWTConfig):
        """Register a JWT configuration for a specific token issuer."""
        if config.issuer and config.issuer != issuer:
            raise ValueError(
                f"Config issuer '{config.issuer}' doesn't match registered issuer '{issuer}'"
            )
        self._source_configs[issuer] = config

    def set_default_config(self, config: JWTConfig):
        """Set a default config for tokens without a recognized issuer."""
        self._default_config = config

    def verify_token(self, token: str) -> Dict[str, Any]:
        """
        Verify a token by determining its source from the issuer claim
        and applying the appropriate verification configuration.
        
        The token's signature is ALWAYS verified with the correct key
        and algorithm allowlist for the identified source.
        """
        try:
            unverified_header = jwt.get_unverified_header(token)
        except jwt.exceptions.DecodeError as e:
            raise jwt.InvalidTokenError(f"Invalid token header: {e}")

        # Peek at unverified claims ONLY to determine the issuer for key selection.
        # The token will be fully verified below with the correct key.
        try:
            unverified_payload = jwt.decode(
                token,
                options={
                    "verify_signature": False,
                    "verify_exp": False,
                },
                algorithms=["HS256", "HS384", "HS512", "RS256", "RS384", "RS512",
                             "ES256", "ES384", "ES512", "PS256", "PS384", "PS512"],
            )
        except jwt.exceptions.DecodeError as e:
            raise jwt.InvalidTokenError(f"Cannot decode token payload: {e}")

        issuer = unverified_payload.get("iss")

        config = None
        if issuer and issuer in self._source_configs:
            config = self._source_configs[issuer]
        elif self._default_config:
            config = self._default_config
        else:
            raise jwt.InvalidTokenError(
                f"No configuration found for issuer '{issuer}' and no default configured"
            )

        # Now perform full, secure verification
        token_algorithm = unverified_header.get("alg")
        if token_algorithm not in config.allowed_algorithms:
            raise jwt.InvalidTokenError(
                f"Token algorithm '{token_algorithm}' is not allowed for issuer '{issuer}'. "
                f"Allowed: {config.allowed_algorithms}"
            )

        verification_key = config.get_verification_key(token_algorithm)

        decode_options = {
            "verify_signature": True,
            "verify_exp": True,
            "verify_nbf": True,
            "verify_iat": True,
            "require": list(config.required_claims),
        }

        decode_kwargs = {
            "algorithms": list(config.allowed_algorithms),
            "options": decode_options,
            "leeway": datetime.timedelta(seconds=config.leeway),
        }

        if config.issuer:
            decode_kwargs["issuer"] = config.issuer
            decode_options["verify_iss"] = True

        if config.audience:
            decode_kwargs["audience"] = config.audience
            decode_options["verify_aud"] = True

        payload = jwt.decode(token, verification_key, **decode_kwargs)

        return payload


