def create_app() -> Flask:
    """Create and configure a Flask application with JWT authentication."""
    app = Flask(__name__)

    # In production, these would come from secure configuration (vault, env vars, etc.)
    # Here we show the pattern of loading from environment.
    internal_config = JWTConfig(
        secret_key=os.environ.get("JWT_SECRET_KEY", "a" * 64),  # Must be >= 32 chars
        allowed_algorithms=["HS256"],
        issuer="internal-auth-service",
        audience="internal-api",
        required_claims=["exp", "iat", "sub"],
        leeway=5,
    )

    jwt_manager = JWTManager(app, config=internal_config)

    # Optional: register a blocklist checker
    _blocklist = set()

    @jwt_manager.token_blocklist_check
    def check_blocklist(jti: str) -> bool:
        return jti in _blocklist

    # Optional: register a user lookup
    @jwt_manager.user_lookup_callback
    def lookup_user(payload: Dict[str, Any]):
        # In production, look up user from database
        return {"id": payload["sub"], "claims": payload}

    # --- Routes ---

    @app.route("/login", methods=["POST"])
    def login():
        data = request.get_json()
        username = data.get("username")
        password = data.get("password")

        # In production, validate credentials against a real auth system
        if username == "admin" and password == "secret":
            access_token = jwt_manager.create_token(
                subject=username,
                algorithm="HS256",
                additional_claims={"role": "admin"},
                expires_delta=datetime.timedelta(minutes=15),
                token_type="access",
            )
            refresh_token = jwt_manager.create_token(
                subject=username,
                algorithm="HS256",
                expires_delta=datetime.timedelta(days=7),
                token_type="refresh",
            )
            return jsonify({
                "access_token": access_token,
                "refresh_token": refresh_token,
            })
        return jsonify({"error": "Invalid credentials"}), 401

    @app.route("/protected", methods=["GET"])
    @jwt_manager.jwt_required(token_type="access")
    def protected():
        return jsonify({
            "message": "Access granted",
            "user": g.jwt_subject,
            "payload": g.jwt_payload,
        })

    @app.route("/refresh", methods=["POST"])
    @jwt_manager.jwt_required(token_type="refresh")
    def refresh():
        new_access_token = jwt_manager.create_token(
            subject=g.jwt_subject,
            algorithm="HS256",
            expires_delta=datetime.timedelta(minutes=15),
            token_type="access",
        )
        return jsonify({"access_token": new_access_token})

    @app.route("/optional", methods=["GET"])
    @jwt_manager.jwt_required(token_type="access", optional=True)
    def optional_auth():
        if g.jwt_payload:
            return jsonify({"message": f"Hello, {g.jwt_subject}!"})
        return jsonify({"message": "Hello, anonymous!"})

    @app.route("/logout", methods=["POST"])
    @jwt_manager.jwt_required(token_type="access")
    def logout():
        jti = g.jwt_payload.get("jti")
        if jti:
            _blocklist.add(jti)
        return jsonify({"message": "Token revoked"})

    return app


